#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,m,k,a[101][101],s[101][101];
    cin>>n>>m>>k;
    for(int i=1;i<=n;i++){
        string x;
        cin>>x;
        for(int j=1;j<=m;j++){
            a[i][j]=x[j-1]-'0';
            s[i][j]=s[i-1][j]+s[i][j-1]+a[i][j]-s[i-1][j-1];
        }
    }
    int ans=100000;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            for(int x=i;x<=n;x++){
                for(int y=j;y<=m;y++){
                    if(s[x][y]-s[i-1][y]-s[x][j-1]+s[i-1][j-1]>=k)ans=min(ans,(x-i+1)*(y-j+1));
                }
            }
        }
    }
    if(ans==100000)cout<<0;
    else cout<<ans;
    return 0;
}
